/**
 * connection-registry.ts — MOTHER v81.8 — Ciclo 189
 *
 * Registry of all modules generated by DGM and their connection status.
 * Implements R27: Every new DGM module MUST be registered here with status CONNECTED or ORPHAN.
 * Modules with ORPHAN status for more than 2 cycles must be connected or archived.
 *
 * Scientific basis:
 * - Conselho dos 6 IAs C188 — diagnóstico unânime "Síndrome do Código Orphan"
 * - Lehman (1980) — "Programs, Life Cycles, and Laws of Software Evolution" — IEEE
 *   Lei de Lehman: sistemas E-type crescem em complexidade sem intervenção ativa.
 * - CMMI Level 3 (Defined) — requires documented process for module lifecycle management
 *
 * @module connection-registry
 * @version 1.0.0
 * @cycle C189
 * @rule R27
 */

export type ModuleStatus = 'CONNECTED' | 'ORPHAN' | 'ARCHIVED' | 'DEPRECATED';

export interface ModuleRegistration {
  name: string;
  path: string;
  exportedFunction: string;
  importTarget: string;
  status: ModuleStatus;
  cycleCreated: number;
  cycleConnected?: number;
  cycleArchived?: number;
  description: string;
  priority: 'P0' | 'P1' | 'P2' | 'LOW';
  councilDecision?: string;
}

