/**
 * Returns all modules with ORPHAN status.
 * Used by DGM orchestrator to identify modules needing connection.
 */
export function getOrphanModules(): ModuleRegistration[] {
  return CONNECTION_REGISTRY.filter(m => m.status === 'ORPHAN');
}

/**
 * Returns modules that have been ORPHAN for more than 2 cycles.
 * These MUST be connected or archived per R27.
 * @param currentCycle - The current cycle number
 */
export function getCriticalOrphans(currentCycle: number): ModuleRegistration[] {
  return CONNECTION_REGISTRY.filter(
    m => m.status === 'ORPHAN' && (currentCycle - m.cycleCreated) > 2,
  );
}

/**
 * Returns a summary of the registry state.
 */
export function getRegistrySummary(): {
  total: number;
  connected: number;
  orphan: number;
  archived: number;
  deprecated: number;
  orphanPercentage: number;
} {
  const total = CONNECTION_REGISTRY.length;
  const connected = CONNECTION_REGISTRY.filter(m => m.status === 'CONNECTED').length;
  const orphan = CONNECTION_REGISTRY.filter(m => m.status === 'ORPHAN').length;
  const archived = CONNECTION_REGISTRY.filter(m => m.status === 'ARCHIVED').length;
  const deprecated = CONNECTION_REGISTRY.filter(m => m.status === 'DEPRECATED').length;

  return {
    total,
    connected,
    orphan,
    archived,
    deprecated,
    orphanPercentage: Math.round((orphan / total) * 100),
  };
}
